  "instructions": {
    "text_instructions": [
      {
        "id": "01f0fd121e191ec189a9483105431d29",
        "content": [
          "Internal Transfers: \r\n",
          "Internal transfers represent money moving between eToro Money and the Trading Platform.\r\n",
          "Each internal transfer appears as two separate rows:\r\n",
          "an eToro Money cashout with a corresponding Trading Platform deposit, or\r\n",
          "a Trading Platform cashout with a corresponding eToro Money deposit.\r\n",
          "\r\n",
          "These rows are mirror movements of the same internal transfer flow.\r\n",
          "\r\n",
          "\r\n",
          "\r\n",
          "\r\n",
          "Bincode full list table is the authoritative master list of all bins, including unused and blacklisted bins. Deposit Attempts is a transaction table; its BinCode is only the bin used in that specific attempt, not the full bin universe. For general bin questions, use Bin Repository. Only use Deposit Attempts when the question is about actual deposit activity by bin."
        ]
      }
    ],
    "join_specs": [
      {
        "id": "01f0fd0566e91068ae9d7f300ddfe37f",
        "left": {
