          "alias": "vg_payments_mimo_basedonddrallplatfrommimo_for_genie"
        },
        "right": {
          "identifier": "main.bi_output.vg_fact_billingwithdraw_for_genie",
          "alias": "vg_fact_billingwithdraw_for_genie"
        },
        "sql": [
          "`vg_payments_mimo_basedonddrallplatfrommimo_for_genie`.`TransactionID` = `vg_fact_billingwithdraw_for_genie`.`WithdrawPaymentID`",
          "--rt=FROM_RELATIONSHIP_TYPE_MANY_TO_ONE--"
        ],
        "instruction": [
          "Use this join only for TradingPlatform withdrawal rows.\n",
          "TransactionID represents Billing WithdrawPaymentID.\n",
          "BillingWithdraw does not contain canonical USD amounts – AmountUSD should be taken from MIMO.\n",
          "Expect NULLs for eMoney rows."
        ]
      }
